  if (cRes.statusCode >= 400) {
    throw new Error("Contact create failed: " + cRes.statusCode + " " + JSON.stringify(cRes.body || {}));
  }
  contact = ((((cRes.body || {})._embedded || {}).contacts || [])[0] || {});
