const row = $json;
if (row.cobranza_agent_should_reply === false) return { json: { ...row, cobranza_send_status: "skipped_no_reply_needed" } };
const leadId = Number(row.lead_id || 0);
if (!leadId) return { json: { ...row, cobranza_send_status: "skipped_no_lead" } };
const content = String(row.cobranza_reply || row.cobranza_agent_reply_text || "Recibimos tu comprobante.").trim() || "Recibimos tu comprobante.";

async function req(method, path, body) {
  return await this.helpers.httpRequest({
    method,
    url: CFG.baseUrl + path,
    headers: {
      Authorization: "Bearer " + CFG.token,
      "Content-Type": "application/json",
    },
    body,
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
}

async function createManualReviewArtifacts(leadId, responsibleUserId, reason, row) {
  const noteText = [
    "Cobranza requiere revision manual desde ruta conversacional.",
    "Motivo: " + String(reason || "sin motivo"),
    "Documento: " + String(row.cobranza_documento || ""),
    "Mensaje cliente: " + String(row.message_text || ""),
    "Intent: " + String(row.cobranza_agent_intent || ""),
    "Confidence: " + String(row.cobranza_agent_confidence || ""),
  ].join(" | ");
  await req("POST", "/api/v4/leads/" + leadId + "/notes", [{ note_type: "common", params: { text: noteText } }]);
  await req("POST", "/api/v4/tasks", [{
    text: "Revisar manualmente chat de cobranza en lead " + leadId + ". Motivo: " + String(reason || "sin motivo"),
    complete_till: Math.floor(Date.now() / 1000) + 86400,
    entity_id: Number(leadId),
    entity_type: "leads",
    responsible_user_id: Number(responsibleUserId || 14811623),
  }]);
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function compact(value, limit) {
  try {
    const s = JSON.stringify(value || {});
    return s.length > limit ? s.slice(0, limit) + "...(trunc)" : s;
  } catch (e) {
    const s = String(value || "");
    return s.length > limit ? s.slice(0, limit) + "...(trunc)" : s;
  }
}

async function latestOutgoingMarker(leadId) {
  const evRes = await req(
    "GET",
    "/api/v4/events?limit=20&filter[entity]=leads&filter[entity_id]=" +
      Number(leadId) +
      "&filter[type][]=outgoing_chat_message"
  );
  if (evRes.statusCode >= 400) {
    return { marker: "", http: Number(evRes.statusCode || 0), createdAt: 0 };
  }
  const ev = ((((evRes.body || {})._embedded || {}).events || [])[0] || {});
  return {
    marker: String(ev.id || ""),
    http: Number(evRes.statusCode || 0),
    createdAt: Number(ev.created_at || 0),
  };
}

const before = await latestOutgoingMarker(leadId);
if (row.cobranza_manual_review_required && !row.cobranza_agent_should_process_payment) {
  await createManualReviewArtifacts(
    leadId,
    row.cobranza_responsible_user_id,
    row.cobranza_manual_review_reason || row.cobranza_agent_reason,
    row
  );
}
const fieldRes = await req("PATCH", "/api/v4/leads", [{
  id: leadId,
  custom_fields_values: [{
    field_id: Number(CFG.fieldIds.respuesta_ia),
    values: [{ value: content }],
  }],
}]);
let sendRes = { statusCode: 0, body: { skipped: true } };
let after = before;
if (fieldRes.statusCode < 400) {
  await sleep(600);
  sendRes = await req("POST", "/api/v2/salesbot/run", [{
    bot_id: Number(CFG.salesbotId),
    entity_id: leadId,
    entity_type: 2,
  }]);
  if (sendRes.statusCode < 400) {
    for (let i = 0; i < 5; i += 1) {
      await sleep(1200);
      after = await latestOutgoingMarker(leadId);
      if (String(after.marker || "") && String(after.marker || "") !== String(before.marker || "")) break;
    }
  }
}
const fieldBody = compact(fieldRes.body, 600);
const bodyTxt = compact(sendRes.body, 600);
const delivered = String(after.marker || "") !== String(before.marker || "") && String(after.marker || "") !== "";
const ok = fieldRes.statusCode < 400 && sendRes.statusCode < 400 && delivered;
const status = ok
  ? "sent"
  : fieldRes.statusCode >= 400
    ? "failed_reply_field_update"
    : sendRes.statusCode >= 400
      ? "failed_salesbot_run"
      : "failed_no_outgoing_chat";

return {
  json: {
    ...row,
    cobranza_send_status: status,
    cobranza_reply_field_http: Number(fieldRes.statusCode || 0),
    cobranza_reply_field_body: fieldBody,
    cobranza_send_http: Number(sendRes.statusCode || 0),
    cobranza_send_body: bodyTxt,
    cobranza_send_mode: "lead_field_plus_salesbot_run",
    cobranza_reply_field_id: Number(CFG.fieldIds.respuesta_ia),
    cobranza_salesbot_id: Number(CFG.salesbotId),
    cobranza_outgoing_before: before.marker || "",
    cobranza_outgoing_after: after.marker || "",
    cobranza_reply_sent: content,
  },
};

let rawOutput = String($json.output || '').trim();
rawOutput = rawOutput
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/gi, '')
  .replace(/^\s*`+|`+\s*$/g, '')
  .trim();

let parsed = null;
try { parsed = JSON.parse(rawOutput); } catch {}
if (!parsed) {
  const start = rawOutput.indexOf('{');
  const end = rawOutput.lastIndexOf('}');
  if (start !== -1 && end > start) {
    try { parsed = JSON.parse(rawOutput.slice(start, end + 1)); } catch {}
  }
}

const base = $('Detectar Cobranza Lead').item.json;
const text = String(base.message_text || '').trim();
const hasAttachment = Boolean(base.is_image || base.cobranza_is_pdf || base.is_document || base.is_media);
const isPaid = Boolean(base.cobranza_is_paid)
  || (base.cobranza_saldo_actual != null && Number(base.cobranza_saldo_actual) <= 0);
const paymentRegex = /(abon|abono|pago|pagado|pague|pagu[e?]|transfer|deposit|comprobante|recibo|spei|folio|adjunt|envi[o?]|mand[o?])/i;
const promiseRegex = /(ahorita|ahora|en un momento|enseguida|lo mando|se lo mando|te lo mando|ya casi|mas tarde|al rato)/i;
const suggestsPayment = paymentRegex.test(text);
const suggestsPromise = promiseRegex.test(text) && !hasAttachment;
const isPlainAcknowledgement = /^(gracias|ok|vale|perfecto|entendido|de acuerdo|listo|ya quedo|si)\b/i.test(text);

function toNumber(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

if (!parsed || typeof parsed !== 'object') parsed = {};

const allowedIntents = new Set(['payment_evidence', 'payment_promise', 'question', 'conversation', 'manual_review']);
const intent = allowedIntents.has(String(parsed.intent || '').trim())
  ? String(parsed.intent).trim()
  : (hasAttachment ? 'payment_evidence' : suggestsPromise ? 'payment_promise' : suggestsPayment ? 'manual_review' : 'conversation');

let shouldProcess = hasAttachment;
if (typeof parsed.should_process_payment === 'boolean') {
  shouldProcess = Boolean(parsed.should_process_payment) || hasAttachment;
} else {
  shouldProcess = hasAttachment || (suggestsPayment && !suggestsPromise) || intent === 'payment_evidence';
}

const fallbackReply = hasAttachment
  ? 'Recibimos tu comprobante. Lo estamos validando.'
  : suggestsPromise
    ? 'Gracias. Quedamos atentos a tu comprobante para validar el abono.'
    : 'Recibimos tu mensaje. Si gustas, comparte tu comprobante para validar el pago.';

const shouldReply = typeof parsed.should_reply === 'boolean' ? parsed.should_reply : true;
let replyText = String(parsed.reply_text || fallbackReply).trim() || fallbackReply;
const amountHint = toNumber(parsed.amount_hint ?? parsed.monto);
const confidence = Number.isFinite(Number(parsed.confidence)) ? Math.max(0, Math.min(1, Number(parsed.confidence))) : 0;
let needsManualReview = typeof parsed.needs_manual_review === 'boolean'
  ? parsed.needs_manual_review
  : intent === 'manual_review';
let reason = String(parsed.reason || '').trim();

if (isPaid && !hasAttachment) {
  replyText = isPlainAcknowledgement
    ? 'Gracias. Tu pago ya fue registrado y tu saldo se encuentra liquidado.'
    : 'Tu pago ya fue registrado y tu saldo se encuentra liquidado. Si necesitas ayuda adicional, un asesor puede apoyarte.';
  shouldProcess = false;
  needsManualReview = false;
}

if (isPaid && hasAttachment) {
  replyText = 'Recibimos tu comprobante. Tu factura ya aparece liquidada, asi que un asesor revisara el chat manualmente.';
  shouldProcess = true;
  needsManualReview = true;
  reason = reason || 'Lead liquidado con nueva evidencia de pago';
}

if (!hasAttachment && needsManualReview) {
  shouldProcess = false;
  replyText = replyText || 'Recibimos tu mensaje. Un asesor revisara el chat para validar el siguiente paso.';
}

return [{
  json: {
    ...base,
    cobranza_agent_raw_output: rawOutput,
    cobranza_agent_intent: intent,
    cobranza_agent_should_process_payment: Boolean(shouldProcess),
    cobranza_agent_should_reply: Boolean(shouldReply),
    cobranza_agent_reply: replyText,
    cobranza_agent_reply_text: replyText,
    cobranza_agent_amount_hint: amountHint,
    cobranza_agent_confidence: confidence,
    cobranza_agent_needs_manual_review: Boolean(needsManualReview),
    cobranza_agent_reason: reason,
    cobranza_manual_review_required: Boolean(needsManualReview),
    cobranza_manual_review_reason: reason,
    cobranza_reply: !Boolean(shouldProcess) ? replyText : (base.cobranza_reply || ''),
  }
}];
